    fn usort_sorts_and_reindexes() {
        // Out-of-order keys 5/2/9 collapse to 0/1/2; usort returns true.
        assert_eq!(
            vm_stdout(b"<?php $a=[5=>'x',2=>'y',9=>'z']; $r=usort($a,fn($p,$q)=>$p<=>$q); echo ($r?'T':'F'),$a[0],$a[1],$a[2];"),
            b"Txyz"
        );
    }

